import{_ as o,C as t,o as l,c as n,j as a,a as c,E as s,w as p,a2 as h}from"./chunks/framework.BcTx5ZBM.js";const _=JSON.parse('{"title":"What is a Particle System?","description":"","frontmatter":{},"headers":[],"relativePath":"0-welcome/foreword.md","filePath":"0-welcome/foreword.md","lastUpdated":null}'),m={name:"0-welcome/foreword.md"};function d(u,e,f,y,g,b){const i=t("ParticleDemo"),r=t("ClientOnly");return l(),n("div",null,[e[0]||(e[0]=a("h1",{id:"what-is-a-particle-system",tabindex:"-1"},[c("What is a Particle System? "),a("a",{class:"header-anchor",href:"#what-is-a-particle-system","aria-label":'Permalink to "What is a Particle System?"'},"​")],-1)),s(r,null,{default:p(()=>[s(i)]),_:1}),e[1]||(e[1]=h('<p>A <strong>particle system</strong> is a technique for rendering many small, semi-transparent objects — particles — to simulate complex visual effects. Fire, smoke, rain, sparks, explosions, magic spells, trails, and starfields are all particle systems.</p><p>Each particle has a position, velocity, color, size, and a remaining lifetime. The particle system updates all particles each frame: it moves them, ages them, applies forces, and removes them when they die. It also spawns new particles at a configured rate, keeping the total count stable.</p><p>The individual particles are simple. The collective behavior is not.</p><h2 id="why-particle-systems-matter" tabindex="-1">Why Particle Systems Matter <a class="header-anchor" href="#why-particle-systems-matter" aria-label="Permalink to &quot;Why Particle Systems Matter&quot;">​</a></h2><p>Particle systems are the first place where engine architecture stops being optional.</p><p>A single particle is a few bytes of data. A hundred particles is a loop. Ten thousand particles is a memory layout problem. A hundred thousand particles is a simulation architecture problem.</p><p>The transition from &quot;it works&quot; to &quot;it breaks&quot; happens at different thresholds depending on how the system is built. That threshold is the subject of this guide.</p><h2 id="where-this-is-going" tabindex="-1">Where This Is Going <a class="header-anchor" href="#where-this-is-going" aria-label="Permalink to &quot;Where This Is Going&quot;">​</a></h2><p>The jygame engine contains a complete particle system — CPU simulation, GPU compute, WebAssembly acceleration, multiple renderers, composable modifiers, and configurable storage backends. Every part of it exists because the naive approach fails at some threshold.</p><p>This guide will walk through each part, starting with the foundations and building up to the full system.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Basic JavaScript: variables, functions, arrays, objects, loops.</p>',12))])}const P=o(m,[["render",d]]);export{_ as __pageData,P as default};
